import React from 'react';
import { IconMap } from '../../assets/Icons';
import { useSeparator, ResponsiveElement } from "../../factory";
import type { IIconProps } from '@lmb-it/kitsconcerto-types';
import { useKitsTheme } from "../../contexts/Theme";

const SIZE_MAP: Record<string, number> = {
    '2xs': 12,
    'xs': 14,
    'sm': 16,
    'md': 18,
    'lg': 20,
    'xl': 24,
};
export function Icon({ name, size = 'lg', color, strokeWidth, ...rest }: IIconProps) {
    const resolvedName = typeof name === 'string' && name.startsWith('pi pi-') ? name.slice(6) : name;
    const IconComponent = typeof resolvedName === 'string' ? IconMap[resolvedName as any] : resolvedName;
    const { cssProps, nativeProps } = useSeparator<HTMLSpanElement>(rest);
    const { resolveToken } = useKitsTheme();

    if (!IconComponent) return null;

    const numericSize = typeof size === 'number' ? size : (SIZE_MAP[size] ?? 18);
    const resolvedColor = color ? resolveToken(color) : undefined;

    return (
        <ResponsiveElement
            as="Box"
            cssProps={cssProps}
            nativeProps={{ ...nativeProps, style: { display: 'inline-flex', alignItems: 'center' } }}
        >
            <IconComponent size={numericSize} color={resolvedColor} strokeWidth={strokeWidth} />
        </ResponsiveElement>
    );
}

export default Icon;
